// Validate payload structure
const payload = msg.payload;
if (!payload || !payload.sensors || !payload.machine_status) {
    node.warn('Invalid payload, skipping');
    return null;
}

// Enrich with received timestamp
msg.payload.received_at = new Date().toISOString();
msg.payload.row = payload.row || 0;

return msg;

// Maintain rolling buffer of last 60 readings
const BUFFER_SIZE = 60;
const SENSOR_GROUPS = ['vibration', 'temperature', 'pressure', 'flow_rate'];

if (!context.get('buffer')) {
    context.set('buffer', []);
}

let buffer = context.get('buffer');
buffer.push(msg.payload);

if (buffer.length > BUFFER_SIZE) {
    buffer = buffer.slice(-BUFFER_SIZE);
}

context.set('buffer', buffer);

// Need at least 5 readings for trend calc
if (buffer.length < 5) {
    return null;
}

msg.payload.buffer_size = buffer.length;
msg.payload.buffer = buffer;

return msg;

const buffer = msg.payload.buffer;
const SENSOR_GROUPS = ['vibration', 'temperature', 'pressure', 'flow_rate'];

function extractSeries(buf, group) {
    return buf.map(r => r.sensors[group] || 0);
}

function rollingAvg(arr) {
    return arr.reduce((a, b) => a + b, 0) / arr.length;
}

function linearSlope(arr) {
    const n = arr.length;
    if (n < 2) return 0;
    const xMean = (n - 1) / 2;
    const yMean = rollingAvg(arr);
    let num = 0, den = 0;
    for (let i = 0; i < n; i++) {
        num += (i - xMean) * (arr[i] - yMean);
        den += (i - xMean) ** 2;
    }
    return den > 0 ? num / den : 0;
}

function rateOfChange(arr) {
    if (arr.length < 2) return 0;
    return arr[arr.length - 1] - arr[arr.length - 2];
}

function stdDev(arr) {
    const mean = rollingAvg(arr);
    const variance = arr.reduce((sum, v) => sum + (v - mean) ** 2, 0) / arr.length;
    return Math.sqrt(variance);
}

const trends = {};
const thresholds = {
    vibration:   { warning: 4.5, critical: 7.0, normal_min: 0,   normal_max: 4.5,  invert: false },
    temperature: { warning: 85,  critical: 95,  normal_min: 60,  normal_max: 85,   invert: false },
    pressure:    { warning: 8.5, critical: 10,  normal_min: 4,   normal_max: 8.5,  invert: false },
    flow_rate:   { warning: 110, critical: 90,  normal_min: 120, normal_max: 200,  invert: true  },
};

for (const group of SENSOR_GROUPS) {
    const series = extractSeries(buffer, group);
    const t = thresholds[group];
    const current = series[series.length - 1];
    const avg = rollingAvg(series);
    const slope = linearSlope(series);
    const roc = rateOfChange(series);
    const std = stdDev(series);

    // Status assessment
    let status = 'NORMAL';
    if (t.invert) {
        if (current <= t.critical) status = 'CRITICAL';
        else if (current <= t.warning) status = 'WARNING';
    } else {
        if (current >= t.critical) status = 'CRITICAL';
        else if (current >= t.warning) status = 'WARNING';
    }

    // Trend direction
    const trending = t.invert
        ? (slope < -0.05 ? 'DEGRADING' : slope > 0.05 ? 'IMPROVING' : 'STABLE')
        : (slope > 0.05  ? 'DEGRADING' : slope < -0.05 ? 'IMPROVING' : 'STABLE');

    trends[group] = {
        current: Math.round(current * 100) / 100,
        avg_60: Math.round(avg * 100) / 100,
        slope: Math.round(slope * 10000) / 10000,
        rate_of_change: Math.round(roc * 1000) / 1000,
        std_dev: Math.round(std * 1000) / 1000,
        status,
        trending,
        history: series.slice(-20), // last 20 for sparkline
    };
}

// Overall machine assessment
const critical_count = Object.values(trends).filter(t => t.status === 'CRITICAL').length;
const warning_count  = Object.values(trends).filter(t => t.status === 'WARNING').length;
const degrading_count = Object.values(trends).filter(t => t.trending === 'DEGRADING').length;

let overall_status = 'NORMAL';
if (critical_count >= 1) overall_status = 'CRITICAL';
else if (warning_count >= 2 || (warning_count >= 1 && degrading_count >= 2)) overall_status = 'WARNING';

msg.payload.trends = trends;
msg.payload.overall_status = overall_status;
msg.payload.anomaly_detected = overall_status !== 'NORMAL';

// Remove buffer from payload (too large for forwarding)
delete msg.payload.buffer;

return msg;

// Prepare compact snapshot for Claude/AI API
const p = msg.payload;

const snapshot = {
    timestamp: p.ts,
    machine_status: p.machine_status,
    health_score: p.health_score,
    overall_status: p.overall_status,
    sensors: {}
};

for (const [group, trend] of Object.entries(p.trends)) {
    snapshot.sensors[group] = {
        current: trend.current,
        avg_60_readings: trend.avg_60,
        trend: trend.trending,
        status: trend.status,
        rate_of_change: trend.rate_of_change,
    };
}

msg.payload = {
    snapshot,
    raw_payload: p,
};

return msg;

if (msg.statusCode !== 200) {
    node.warn('AI API error: ' + msg.statusCode);
    return null;
}

const ai = msg.payload;

// Forward to WebSocket for dashboard
msg.topic = 'ai_recommendation';
msg.payload = {
    type: 'ai_recommendation',
    ...ai,
    received_at: new Date().toISOString(),
};

return msg;
